import{CATEGORY_DESCRIPTIONS as e,CATEGORY_GUIDE_QUESTIONS as t}from"./category-guide-DeT8P54g.js";var n={name:`Depressive and Bipolar Disorders`,disorders:{"Major Depressive Disorder":{code:`296.33`,criteria:{A:{text:`Five or more of the following symptoms during the same 2-week period`,symptoms:[{id:`depressed_mood`,text:`Depressed mood most of the day, nearly every day`,weight:1},{id:`anhedonia`,text:`Markedly diminished interest or pleasure in all, or almost all, activities`,weight:1},{id:`weight_change`,text:`Significant weight loss or gain, or decrease/increase in appetite`,weight:.8},{id:`sleep_disturbance`,text:`Insomnia or hypersomnia nearly every day`,weight:.8},{id:`psychomotor`,text:`Psychomotor agitation or retardation`,weight:.7},{id:`fatigue`,text:`Fatigue or loss of energy nearly every day`,weight:.9},{id:`worthlessness`,text:`Feelings of worthlessness or excessive guilt`,weight:.8},{id:`concentration`,text:`Diminished ability to think or concentrate, or indecisiveness`,weight:.7},{id:`suicidal`,text:`Recurrent thoughts of death, suicidal ideation, or suicide attempt`,weight:1}],threshold:5},B:{text:`Symptoms cause clinically significant distress or impairment`,weight:1},C:{text:`Not attributable to substance or medical condition`,weight:.9}},specifiers:[`mild`,`moderate`,`severe`,`with psychotic features`,`in partial remission`,`in full remission`]},"Persistent Depressive Disorder (Dysthymia)":{code:`300.4`,criteria:{A:{text:`Depressed mood for most of the day, for more days than not, for at least 2 years`,weight:1},B:{text:`Two or more of the following while depressed`,symptoms:[{id:`poor_appetite`,text:`Poor appetite or overeating`,weight:.7},{id:`insomnia_hypersomnia`,text:`Insomnia or hypersomnia`,weight:.7},{id:`low_energy`,text:`Low energy or fatigue`,weight:.8},{id:`low_self_esteem`,text:`Low self-esteem`,weight:.8},{id:`poor_concentration`,text:`Poor concentration or difficulty making decisions`,weight:.7},{id:`hopelessness`,text:`Feelings of hopelessness`,weight:.9}],threshold:2},C:{text:`Never without symptoms for more than 2 months at a time`,weight:.9}}},"Bipolar I Disorder":{code:`296.xx`,criteria:{A:{text:`At least one manic episode`,symptoms:[{id:`elevated_mood`,text:`Abnormally and persistently elevated, expansive, or irritable mood`,weight:1},{id:`increased_activity`,text:`Abnormally and persistently increased goal-directed activity or energy`,weight:1},{id:`grandiosity`,text:`Inflated self-esteem or grandiosity`,weight:.8},{id:`decreased_sleep`,text:`Decreased need for sleep`,weight:.7},{id:`pressured_speech`,text:`More talkative than usual or pressure to keep talking`,weight:.8},{id:`flight_ideas`,text:`Flight of ideas or racing thoughts`,weight:.8},{id:`distractibility`,text:`Distractibility`,weight:.7},{id:`risky_behavior`,text:`Excessive involvement in activities with high potential for painful consequences`,weight:.9}],threshold:3}}},"Bipolar II Disorder":{code:`296.89`,criteria:{A:{text:`At least one hypomanic episode and one major depressive episode`,weight:1},B:{text:`Never had a manic episode`,weight:1}}},"Cyclothymic Disorder":{code:`301.13`,criteria:{A:{text:`For at least 2 years, numerous periods with hypomanic symptoms and periods with depressive symptoms`,weight:1},B:{text:`Never without symptoms for more than 2 months`,weight:.9}}},"Disruptive Mood Dysregulation Disorder":{code:`296.99`,criteria:{A:{text:`Severe recurrent temper outbursts inconsistent with developmental level`,weight:1},B:{text:`Temper outbursts occurring three or more times per week`,weight:.9},C:{text:`Mood between outbursts is persistently irritable or angry`,weight:.9}}},"Premenstrual Dysphoric Disorder":{code:`625.4`,criteria:{A:{text:`Five or more symptoms present in the final week before menses`,symptoms:[{id:`affective_lability`,text:`Marked affective lability`,weight:.9},{id:`irritability_anger`,text:`Marked irritability or anger`,weight:.9},{id:`depressed_mood_pmdd`,text:`Markedly depressed mood`,weight:1},{id:`anxiety_pmdd`,text:`Marked anxiety or tension`,weight:.8},{id:`decreased_interest_pmdd`,text:`Decreased interest in usual activities`,weight:.8},{id:`difficulty_concentration_pmdd`,text:`Difficulty concentrating`,weight:.7},{id:`lethargy_pmdd`,text:`Lethargy, easily fatigued, or lack of energy`,weight:.8},{id:`change_appetite_pmdd`,text:`Marked change in appetite`,weight:.7},{id:`hypersomnia_insomnia_pmdd`,text:`Hypersomnia or insomnia`,weight:.7},{id:`overwhelmed_pmdd`,text:`Feeling overwhelmed or out of control`,weight:.8},{id:`physical_symptoms_pmdd`,text:`Physical symptoms (breast tenderness, bloating)`,weight:.6}],threshold:5},B:{text:`Symptoms improve within a few days after menses onset`,weight:1}}},"Substance/Medication-Induced Depressive Disorder":{code:`293.83`,criteria:{A:{text:`Prominent and persistent disturbance in mood with depressed mood or loss of interest`,weight:1},B:{text:`Evidence that symptoms developed during or soon after substance intoxication/withdrawal or medication exposure`,weight:1}}},"Depressive Disorder Due to Another Medical Condition":{code:`293.83`,criteria:{A:{text:`Prominent and persistent period of depressed mood or loss of interest`,weight:1},B:{text:`Evidence that disturbance is direct pathophysiological consequence of another medical condition`,weight:1}}},"Low-Intensity Depressive Pattern":{code:`311`,criteria:{A:{text:`Subthreshold depressive symptoms causing distress without meeting full criteria`,weight:.8}}},"Unspecified Depressive Disorder":{code:`311`,criteria:{A:{text:`Depressive symptoms causing distress but insufficient information for specific diagnosis`,weight:.7}}}}},r={name:`Anxiety Disorders`,disorders:{"Generalized Anxiety Disorder":{code:`300.02`,criteria:{A:{text:`Excessive anxiety and worry, occurring more days than not for at least 6 months`,weight:1},B:{text:`Difficulty controlling the worry`,weight:.9},C:{text:`Three or more of the following symptoms`,symptoms:[{id:`restlessness`,text:`Restlessness or feeling keyed up or on edge`,weight:.8},{id:`easily_fatigued`,text:`Being easily fatigued`,weight:.7},{id:`difficulty_concentrating`,text:`Difficulty concentrating or mind going blank`,weight:.8},{id:`irritability`,text:`Irritability`,weight:.7},{id:`muscle_tension`,text:`Muscle tension`,weight:.7},{id:`sleep_disturbance_anx`,text:`Sleep disturbance`,weight:.7}],threshold:3}}},"Panic Disorder":{code:`300.01`,criteria:{A:{text:`Recurrent unexpected panic attacks`,weight:1},B:{text:`At least one attack followed by persistent concern or worry about additional attacks, or significant maladaptive change in behavior`,weight:.9},C:{text:`Panic attacks not due to substance or medical condition`,weight:.9}}},"Social Anxiety Disorder (Social Phobia)":{code:`300.23`,criteria:{A:{text:`Marked fear or anxiety about one or more social situations in which the individual is exposed to possible scrutiny`,weight:1},B:{text:`The individual fears they will act in a way that will be negatively evaluated`,weight:.9},C:{text:`Social situations almost always provoke fear or anxiety`,weight:.9},D:{text:`Social situations are avoided or endured with intense fear or anxiety`,weight:.9}}},"Specific Phobia":{code:`300.29`,criteria:{A:{text:`Marked fear or anxiety about a specific object or situation`,weight:1},B:{text:`The phobic object or situation almost always provokes immediate fear or anxiety`,weight:.9},C:{text:`The phobic object or situation is actively avoided or endured with intense fear or anxiety`,weight:.9}}},Agoraphobia:{code:`300.22`,criteria:{A:{text:`Marked fear or anxiety about two or more of: using public transportation, being in open spaces, being in enclosed places, standing in line or being in a crowd, being outside of the home alone`,weight:1},B:{text:`The individual fears or avoids these situations because of thoughts that escape might be difficult or help unavailable`,weight:.9},C:{text:`These situations almost always provoke fear or anxiety`,weight:.9}}},"Substance/Medication-Induced Anxiety Disorder":{code:`293.89`,criteria:{A:{text:`Panic attacks or anxiety is prominent`,weight:1},B:{text:`Evidence that symptoms developed during or soon after substance intoxication/withdrawal or medication exposure`,weight:1}}},"Anxiety Disorder Due to Another Medical Condition":{code:`293.84`,criteria:{A:{text:`Panic attacks or anxiety is prominent`,weight:1},B:{text:`Evidence that disturbance is direct pathophysiological consequence of another medical condition`,weight:1}}},"Other Specified Anxiety Disorder":{code:`300.09`,criteria:{A:{text:`Anxiety symptoms causing distress but not meeting full criteria`,weight:.8}}},"Unspecified Anxiety Disorder":{code:`300.00`,criteria:{A:{text:`Anxiety symptoms causing distress but insufficient information for specific diagnosis`,weight:.7}}}}},i={name:`Trauma- and Stressor-Related Disorders`,disorders:{"Posttraumatic Stress Disorder":{code:`309.81`,criteria:{A:{text:`Exposure to actual or threatened death, serious injury, or sexual violence`,weight:1},B:{text:`One or more intrusion symptoms`,symptoms:[{id:`recurrent_memories`,text:`Recurrent, involuntary, and intrusive distressing memories`,weight:.9},{id:`recurrent_dreams`,text:`Recurrent distressing dreams`,weight:.8},{id:`dissociative_reactions`,text:`Dissociative reactions (flashbacks)`,weight:.9},{id:`psychological_distress`,text:`Intense psychological distress at exposure to cues`,weight:.8},{id:`physiological_reactions`,text:`Marked physiological reactions to cues`,weight:.8}],threshold:1},C:{text:`One or more avoidance symptoms`,symptoms:[{id:`avoid_memories`,text:`Avoidance of memories, thoughts, or feelings`,weight:.9},{id:`avoid_external`,text:`Avoidance of external reminders`,weight:.9}],threshold:1},D:{text:`Two or more negative alterations in cognitions and mood`,symptoms:[{id:`amnesia`,text:`Inability to remember important aspects`,weight:.7},{id:`negative_beliefs`,text:`Persistent negative beliefs about self, others, or world`,weight:.8},{id:`distorted_blame`,text:`Distorted cognitions about cause or consequences`,weight:.7},{id:`negative_emotional`,text:`Persistent negative emotional state`,weight:.8},{id:`diminished_interest`,text:`Markedly diminished interest in activities`,weight:.7},{id:`detachment`,text:`Feelings of detachment or estrangement`,weight:.7},{id:`inability_positive`,text:`Inability to experience positive emotions`,weight:.8}],threshold:2},E:{text:`Two or more alterations in arousal and reactivity`,symptoms:[{id:`irritable_behavior`,text:`Irritable behavior and angry outbursts`,weight:.8},{id:`reckless_behavior`,text:`Reckless or self-destructive behavior`,weight:.8},{id:`hypervigilance`,text:`Hypervigilance`,weight:.8},{id:`exaggerated_startle`,text:`Exaggerated startle response`,weight:.7},{id:`concentration_problems`,text:`Problems with concentration`,weight:.7},{id:`sleep_disturbance_ptsd`,text:`Sleep disturbance`,weight:.7}],threshold:2}}},"Acute Stress Disorder":{code:`308.3`,criteria:{A:{text:`Exposure to actual or threatened death, serious injury, or sexual violation`,weight:1},B:{text:`Nine or more symptoms from any of the five categories (intrusion, negative mood, dissociation, avoidance, arousal)`,threshold:9},C:{text:`Duration is 3 days to 1 month after trauma exposure`,weight:1}}},"Adjustment Disorders":{code:`309.xx`,criteria:{A:{text:`Development of emotional or behavioral symptoms in response to an identifiable stressor(s) within 3 months`,weight:1},B:{text:`Symptoms are clinically significant (marked distress or impairment)`,weight:1},C:{text:`Does not meet criteria for another mental disorder`,weight:.9}}},"Reactive Attachment Disorder":{code:`313.89`,criteria:{A:{text:`Consistent pattern of inhibited, emotionally withdrawn behavior toward adult caregivers`,weight:1},B:{text:`Social and emotional disturbance (limited positive affect, episodes of unexplained irritability, sadness, or fearfulness)`,weight:1},C:{text:`Pattern of extremes of insufficient care`,weight:1}}},"Disinhibited Social Engagement Disorder":{code:`313.89`,criteria:{A:{text:`Pattern of behavior in which child actively approaches and interacts with unfamiliar adults`,weight:1},B:{text:`Behaviors not limited to impulsivity but include socially disinhibited behavior`,weight:.9},C:{text:`Pattern of extremes of insufficient care`,weight:1}}},"Other Specified Trauma- and Stressor-Related Disorder":{code:`309.89`,criteria:{A:{text:`Trauma/stressor-related symptoms causing distress but not meeting full criteria`,weight:.8}}},"Unspecified Trauma- and Stressor-Related Disorder":{code:`309.9`,criteria:{A:{text:`Trauma/stressor-related symptoms causing distress but insufficient information for specific diagnosis`,weight:.7}}}}},a={name:`Personality Disorders`,disorders:{"Borderline Personality Disorder":{code:`301.83`,criteria:{A:{text:`A pervasive pattern of instability of interpersonal relationships, self-image, and affects, and marked impulsivity`,threshold:5,symptoms:[{id:`frantic_abandonment`,text:`Frantic efforts to avoid real or imagined abandonment`,weight:.9},{id:`unstable_relationships`,text:`Unstable and intense interpersonal relationships`,weight:.9},{id:`identity_disturbance`,text:`Identity disturbance`,weight:.9},{id:`impulsivity`,text:`Impulsivity in potentially self-damaging areas`,weight:.8},{id:`suicidal_behavior`,text:`Recurrent suicidal behavior, gestures, or threats`,weight:1},{id:`affective_instability`,text:`Affective instability due to marked reactivity of mood`,weight:.9},{id:`chronic_emptiness`,text:`Chronic feelings of emptiness`,weight:.8},{id:`inappropriate_anger`,text:`Inappropriate, intense anger or difficulty controlling anger`,weight:.8},{id:`transient_paranoid`,text:`Transient, stress-related paranoid ideation or severe dissociative symptoms`,weight:.7}]}}},"Narcissistic Personality Disorder":{code:`301.81`,criteria:{A:{text:`A pervasive pattern of grandiosity, need for admiration, and lack of empathy`,threshold:5,symptoms:[{id:`grandiose_sense`,text:`Grandiose sense of self-importance`,weight:.9},{id:`fantasies_success`,text:`Preoccupation with fantasies of success, power, brilliance`,weight:.8},{id:`special_unique`,text:`Belief that one is special and unique`,weight:.8},{id:`requires_admiration`,text:`Requires excessive admiration`,weight:.9},{id:`sense_entitlement`,text:`Sense of entitlement`,weight:.9},{id:`exploitative`,text:`Interpersonally exploitative`,weight:.8},{id:`lacks_empathy`,text:`Lacks empathy`,weight:.9},{id:`envious`,text:`Often envious of others or believes others are envious`,weight:.7},{id:`arrogant`,text:`Shows arrogant, haughty behaviors or attitudes`,weight:.8}]}}},"Antisocial Personality Disorder":{code:`301.7`,criteria:{A:{text:`A pervasive pattern of disregard for and violation of the rights of others, occurring since age 15`,threshold:3,symptoms:[{id:`failure_conform`,text:`Failure to conform to social norms with respect to lawful behaviors`,weight:.9},{id:`deceitfulness`,text:`Deceitfulness, repeated lying, conning others`,weight:.9},{id:`impulsivity_aspd`,text:`Impulsivity or failure to plan ahead`,weight:.7},{id:`irritability_aggression`,text:`Irritability and aggressiveness, physical fights or assaults`,weight:.9},{id:`reckless_disregard`,text:`Reckless disregard for safety of self or others`,weight:.9},{id:`irresponsible`,text:`Consistent irresponsibility, failure to sustain work or honor financial obligations`,weight:.8},{id:`lack_remorse`,text:`Lack of remorse, indifference to or rationalizing having hurt, mistreated, or stolen from another`,weight:.9}]},B:{text:`Individual is at least age 18`,weight:1},C:{text:`Evidence of Conduct Disorder with onset before age 15`,weight:.9}}},"Histrionic Personality Disorder":{code:`301.50`,criteria:{A:{text:`A pervasive pattern of excessive emotionality and attention seeking`,threshold:5,symptoms:[{id:`uncomfortable_center`,text:`Uncomfortable in situations in which he or she is not the center of attention`,weight:.9},{id:`inappropriate_seductive`,text:`Interaction with others is often characterized by inappropriate sexually seductive or provocative behavior`,weight:.8},{id:`rapidly_shifting`,text:`Displays rapidly shifting and shallow expression of emotions`,weight:.8},{id:`uses_physical`,text:`Consistently uses physical appearance to draw attention to self`,weight:.7},{id:`speech_impressionistic`,text:`Has a style of speech that is excessively impressionistic and lacking in detail`,weight:.7},{id:`self_dramatization`,text:`Shows self-dramatization, theatricality, and exaggerated expression of emotion`,weight:.8},{id:`suggestible`,text:`Is suggestible (easily influenced by others or circumstances)`,weight:.7},{id:`considers_relationships`,text:`Considers relationships to be more intimate than they actually are`,weight:.8}]}}},"Paranoid Personality Disorder":{code:`301.0`,criteria:{A:{text:`A pervasive distrust and suspiciousness of others`,threshold:4,symptoms:[{id:`suspects_exploitation`,text:`Suspects, without sufficient basis, that others are exploiting, harming, or deceiving him or her`,weight:.9},{id:`preoccupied_doubts`,text:`Is preoccupied with unjustified doubts about the loyalty or trustworthiness of friends or associates`,weight:.9},{id:`reluctant_confide`,text:`Is reluctant to confide in others because of unwarranted fear that the information will be used maliciously against him or her`,weight:.8},{id:`reads_hidden`,text:`Reads hidden demeaning or threatening meanings into benign remarks or events`,weight:.8},{id:`persistently_bears`,text:`Persistently bears grudges (is unforgiving of insults, injuries, or slights)`,weight:.8},{id:`perceives_attacks`,text:`Perceives attacks on his or her character or reputation that are not apparent to others and is quick to react angrily or to counterattack`,weight:.9},{id:`recurrent_suspicious`,text:`Has recurrent suspicions, without justification, regarding fidelity of spouse or sexual partner`,weight:.8}]}}},"Schizoid Personality Disorder":{code:`301.20`,criteria:{A:{text:`A pervasive pattern of detachment from social relationships and a restricted range of expression of emotions`,threshold:4,symptoms:[{id:`neither_desires`,text:`Neither desires nor enjoys close relationships, including being part of a family`,weight:.9},{id:`almost_always`,text:`Almost always chooses solitary activities`,weight:.8},{id:`little_interest`,text:`Has little, if any, interest in having sexual experiences with another person`,weight:.7},{id:`takes_pleasure`,text:`Takes pleasure in few, if any, activities`,weight:.8},{id:`lacks_close`,text:`Lacks close friends or confidants other than first-degree relatives`,weight:.9},{id:`appears_indifferent`,text:`Appears indifferent to the praise or criticism of others`,weight:.8},{id:`shows_emotional`,text:`Shows emotional coldness, detachment, or flattened affectivity`,weight:.8}]}}},"Schizotypal Personality Disorder":{code:`301.22`,criteria:{A:{text:`A pervasive pattern of social and interpersonal deficits marked by acute discomfort with, and reduced capacity for, close relationships as well as by cognitive or perceptual distortions and eccentricities of behavior`,threshold:5,symptoms:[{id:`ideas_reference`,text:`Ideas of reference (excluding delusions of reference)`,weight:.8},{id:`odd_beliefs`,text:`Odd beliefs or magical thinking that influences behavior and is inconsistent with subcultural norms`,weight:.8},{id:`unusual_perceptual`,text:`Unusual perceptual experiences, including bodily illusions`,weight:.8},{id:`odd_thinking`,text:`Odd thinking and speech (vague, circumstantial, metaphorical, overelaborate, or stereotyped)`,weight:.8},{id:`suspiciousness_paranoid`,text:`Suspiciousness or paranoid ideation`,weight:.8},{id:`inappropriate_affect`,text:`Inappropriate or constricted affect`,weight:.7},{id:`behavior_appearance`,text:`Behavior or appearance that is odd, eccentric, or peculiar`,weight:.8},{id:`lack_close`,text:`Lack of close friends or confidants other than first-degree relatives`,weight:.8},{id:`excessive_social`,text:`Excessive social anxiety that does not diminish with familiarity and tends to be associated with paranoid fears rather than negative judgments about self`,weight:.8}]}}},"Avoidant Personality Disorder":{code:`301.82`,criteria:{A:{text:`A pervasive pattern of social inhibition, feelings of inadequacy, and hypersensitivity to negative evaluation`,threshold:4,symptoms:[{id:`avoids_occupational`,text:`Avoids occupational activities that involve significant interpersonal contact because of fears of criticism, disapproval, or rejection`,weight:.9},{id:`unwilling_get`,text:`Is unwilling to get involved with people unless certain of being liked`,weight:.9},{id:`shows_restraint`,text:`Shows restraint within intimate relationships because of the fear of being shamed or ridiculed`,weight:.8},{id:`preoccupied_criticized`,text:`Is preoccupied with being criticized or rejected in social situations`,weight:.9},{id:`inhibited_new`,text:`Is inhibited in new interpersonal situations because of feelings of inadequacy`,weight:.8},{id:`views_self`,text:`Views self as socially inept, personally unappealing, or inferior to others`,weight:.9},{id:`unusually_reluctant`,text:`Is unusually reluctant to take personal risks or to engage in any new activities because they may prove embarrassing`,weight:.8}]}}},"Dependent Personality Disorder":{code:`301.6`,criteria:{A:{text:`A pervasive and excessive need to be taken care of that leads to submissive and clinging behavior and fears of separation`,threshold:5,symptoms:[{id:`difficulty_making`,text:`Has difficulty making everyday decisions without an excessive amount of advice and reassurance from others`,weight:.9},{id:`needs_others`,text:`Needs others to assume responsibility for most major areas of his or her life`,weight:.9},{id:`difficulty_expressing`,text:`Has difficulty expressing disagreement with others because of fear of loss of support or approval`,weight:.8},{id:`difficulty_initiating`,text:`Has difficulty initiating projects or doing things on his or her own (because of a lack of self-confidence in judgment or abilities rather than a lack of motivation or energy)`,weight:.8},{id:`goes_excessive`,text:`Goes to excessive lengths to obtain nurturance and support from others, to the point of volunteering to do things that are unpleasant`,weight:.8},{id:`feels_uncomfortable`,text:`Feels uncomfortable or helpless when alone because of exaggerated fears of being unable to care for himself or herself`,weight:.9},{id:`urgently_seeks`,text:`Urgently seeks another relationship as a source of care and support when a close relationship ends`,weight:.8},{id:`unrealistically_preoccupied`,text:`Is unrealistically preoccupied with fears of being left to take care of himself or herself`,weight:.9}]}}},"Obsessive-Compulsive Personality Disorder":{code:`301.4`,criteria:{A:{text:`A pervasive pattern of preoccupation with orderliness, perfectionism, and mental and interpersonal control`,threshold:4,symptoms:[{id:`preoccupied_details`,text:`Is preoccupied with details, rules, lists, order, organization, or schedules to the extent that the major point of the activity is lost`,weight:.8},{id:`shows_perfectionism`,text:`Shows perfectionism that interferes with task completion`,weight:.9},{id:`excessively_devoted`,text:`Is excessively devoted to work and productivity to the exclusion of leisure activities and friendships (not accounted for by obvious economic necessity)`,weight:.8},{id:`overconscientious_scrupulous`,text:`Is overconscientious, scrupulous, and inflexible about matters of morality, ethics, or values (not accounted for by cultural or religious identification)`,weight:.8},{id:`unable_discard`,text:`Is unable to discard worn-out or worthless objects even when they have no sentimental value`,weight:.7},{id:`reluctant_delegate`,text:`Is reluctant to delegate tasks or to work with others unless they submit to exactly his or her way of doing things`,weight:.8},{id:`adopts_miserly`,text:`Adopts a miserly spending style toward both self and others; money is viewed as something to be hoarded for future catastrophes`,weight:.7},{id:`shows_rigidity`,text:`Shows rigidity and stubbornness`,weight:.8}]}}},"Other Specified Personality Disorder":{code:`301.89`,criteria:{A:{text:`Personality disorder traits causing distress but not meeting full criteria`,weight:.8}}},"Unspecified Personality Disorder":{code:`301.9`,criteria:{A:{text:`Personality disorder traits causing distress but insufficient information for specific diagnosis`,weight:.7}}}}},o={name:`Obsessive-Compulsive and Related Disorders`,disorders:{"Obsessive-Compulsive Disorder":{code:`300.3`,criteria:{A:{text:`Presence of obsessions, compulsions, or both`,weight:1},B:{text:`Obsessions or compulsions are time-consuming or cause clinically significant distress or impairment`,weight:1}}},"Body Dysmorphic Disorder":{code:`300.7`,criteria:{A:{text:`Preoccupation with one or more perceived defects or flaws in physical appearance that are not observable or appear slight to others`,weight:1},B:{text:`At some point during the course of the disorder, the individual has performed repetitive behaviors or mental acts in response to the appearance concerns`,weight:.9}}},"Hoarding Disorder":{code:`300.3`,criteria:{A:{text:`Persistent difficulty discarding or parting with possessions, regardless of their actual value`,weight:1},B:{text:`This difficulty is due to a perceived need to save the items and to distress associated with discarding them`,weight:.9},C:{text:`The difficulty discarding possessions results in the accumulation of possessions that congest and clutter active living areas`,weight:1}}},"Trichotillomania (Hair-Pulling Disorder)":{code:`312.39`,criteria:{A:{text:`Recurrent pulling out of one's hair, resulting in hair loss`,weight:1},B:{text:`Repeated attempts to decrease or stop hair pulling`,weight:.9},C:{text:`The hair pulling causes clinically significant distress or impairment`,weight:.9}}},"Excoriation (Skin-Picking) Disorder":{code:`298.8`,criteria:{A:{text:`Recurrent skin picking resulting in skin lesions`,weight:1},B:{text:`Repeated attempts to decrease or stop skin picking`,weight:.9},C:{text:`The skin picking causes clinically significant distress or impairment`,weight:.9}}}}},s={name:`Feeding and Eating Disorders`,disorders:{"Anorexia Nervosa":{code:`307.1`,criteria:{A:{text:`Restriction of energy intake leading to significantly low body weight`,weight:1},B:{text:`Intense fear of gaining weight or becoming fat, or persistent behavior that interferes with weight gain`,weight:1},C:{text:`Disturbance in the way one's body weight or shape is experienced`,weight:.9}}},"Bulimia Nervosa":{code:`307.51`,criteria:{A:{text:`Recurrent episodes of binge eating`,weight:1},B:{text:`Recurrent inappropriate compensatory behaviors to prevent weight gain`,weight:1},C:{text:`Binge eating and compensatory behaviors both occur, on average, at least once a week for 3 months`,weight:.9}}},"Binge-Eating Disorder":{code:`307.51`,criteria:{A:{text:`Recurrent episodes of binge eating`,weight:1},B:{text:`The binge-eating episodes are associated with three or more specified markers (eating rapidly, eating until uncomfortably full, eating large amounts when not physically hungry, eating alone due to embarrassment, feeling disgusted/depressed/guilty)`,threshold:3,weight:.9},C:{text:`Marked distress regarding binge eating`,weight:.9}}},"Avoidant/Restrictive Food Intake Disorder":{code:`307.59`,criteria:{A:{text:`An eating or feeding disturbance (lack of interest in food, avoidance based on sensory characteristics, concern about aversive consequences)`,weight:1},B:{text:`The disturbance leads to persistent failure to meet appropriate nutritional needs`,weight:1}}}}},c={name:`Substance-Related and Addictive Disorders`,disorders:{"Substance Use Disorder":{code:`varies`,criteria:{A:{text:`A problematic pattern of substance use leading to clinically significant impairment or distress, manifested by at least 2 of 11 criteria within a 12-month period`,threshold:2,symptoms:[{id:`tolerance`,text:`Tolerance (need for increased amounts or diminished effect)`,weight:.8},{id:`withdrawal`,text:`Withdrawal symptoms or substance taken to relieve withdrawal`,weight:.9},{id:`taken_larger`,text:`Substance taken in larger amounts or over longer period than intended`,weight:.8},{id:`persistent_desire`,text:`Persistent desire or unsuccessful efforts to cut down or control use`,weight:.9},{id:`time_spent`,text:`Great deal of time spent obtaining, using, or recovering from substance`,weight:.8},{id:`important_activities`,text:`Important social, occupational, or recreational activities given up or reduced`,weight:.9},{id:`continued_despite`,text:`Continued use despite knowledge of physical or psychological problem caused or exacerbated by substance`,weight:.9},{id:`craving`,text:`Craving or strong desire to use substance`,weight:.8}]}}},"Gambling Disorder":{code:`312.31`,criteria:{A:{text:`Persistent and recurrent problematic gambling behavior leading to clinically significant impairment or distress, as indicated by 4 or more of 9 criteria`,threshold:4,weight:1}}}}},l={name:`Neurocognitive Disorders`,disorders:{"Major Neurocognitive Disorder":{code:`varies`,criteria:{A:{text:`Evidence of significant cognitive decline from a previous level of performance in one or more cognitive domains`,weight:1},B:{text:`The cognitive deficits interfere with independence in everyday activities`,weight:1},C:{text:`The cognitive deficits do not occur exclusively in the context of a delirium`,weight:.9}}},"Mild Neurocognitive Disorder":{code:`331.83`,criteria:{A:{text:`Evidence of modest cognitive decline from a previous level of performance in one or more cognitive domains`,weight:1},B:{text:`The cognitive deficits do not interfere with capacity for independence in everyday activities`,weight:.9}}}}},u={name:`Neurodevelopmental Disorders`,disorders:{"Autism Spectrum Disorder":{code:`299.00`,criteria:{A:{text:`Persistent deficits in social communication and social interaction across multiple contexts`,weight:1},B:{text:`Restricted, repetitive patterns of behavior, interests, or activities`,weight:1},C:{text:`Symptoms must be present in early developmental period`,weight:1}}},"Attention-Deficit/Hyperactivity Disorder":{code:`314.01`,criteria:{A:{text:`A persistent pattern of inattention and/or hyperactivity-impulsivity that interferes with functioning or development`,weight:1},B:{text:`Several symptoms present prior to age 12`,weight:.9}}},"Specific Learning Disorder":{code:`315.00`,criteria:{A:{text:`Difficulties learning and using academic skills, as indicated by the presence of at least one of the following symptoms that have persisted for at least 6 months`,weight:1},B:{text:`The affected academic skills are substantially and quantifiably below those expected for the individual's chronological age`,weight:1}}}}},d={name:`Sleep-Wake Disorders`,disorders:{"Insomnia Disorder":{code:`307.42`,criteria:{A:{text:`Dissatisfaction with sleep quantity or quality, with complaints of difficulty initiating or maintaining sleep`,weight:1},B:{text:`The sleep disturbance causes clinically significant distress or impairment`,weight:.9},C:{text:`The sleep difficulty occurs at least 3 nights per week`,weight:.9}}},"Hypersomnolence Disorder":{code:`307.44`,criteria:{A:{text:`Self-reported excessive sleepiness despite a main sleep period lasting at least 7 hours`,weight:1},B:{text:`The hypersomnolence occurs at least three times per week, for at least 3 months`,weight:.9}}},Narcolepsy:{code:`347.00`,criteria:{A:{text:`Recurrent periods of an irrepressible need to sleep, lapsing into sleep, or napping occurring within the same day`,weight:1},B:{text:`At least one of: cataplexy, hypocretin deficiency, or REM sleep latency of ≤15 minutes`,weight:.9}}}}},f={name:`Sexual Dysfunctions`,disorders:{"Delayed Ejaculation":{code:`302.74`,criteria:{A:{text:`Either a marked delay in ejaculation or a marked infrequency or absence of ejaculation, on almost all or all occasions of partnered sexual activity`,weight:1},B:{text:`The symptoms have persisted for a minimum duration of approximately 6 months`,weight:.9}}},"Erectile Disorder":{code:`302.72`,criteria:{A:{text:`At least one of three symptoms: marked difficulty obtaining an erection, marked difficulty maintaining an erection, marked decrease in erectile rigidity`,weight:1},B:{text:`The symptoms have persisted for a minimum duration of approximately 6 months`,weight:.9}}},"Female Orgasmic Disorder":{code:`302.73`,criteria:{A:{text:`Presence of either a marked delay in, marked infrequency of, or absence of orgasm; or a markedly reduced intensity of orgasmic sensations`,weight:1},B:{text:`The symptoms have persisted for a minimum duration of approximately 6 months`,weight:.9}}},"Female Sexual Interest/Arousal Disorder":{code:`302.72`,criteria:{A:{text:`Lack of, or significantly reduced, sexual interest/arousal, as manifested by at least 3 of 6 symptoms`,threshold:3,weight:1},B:{text:`The symptoms have persisted for a minimum duration of approximately 6 months`,weight:.9}}},"Male Hypoactive Sexual Desire Disorder":{code:`302.71`,criteria:{A:{text:`Persistently or recurrently deficient (or absent) sexual/erotic thoughts, fantasies, and desire for sexual activity`,weight:1},B:{text:`The symptoms have persisted for a minimum duration of approximately 6 months`,weight:.9}}},"Premature (Early) Ejaculation":{code:`302.75`,criteria:{A:{text:`A persistent or recurrent pattern of ejaculation occurring during partnered sexual activity within approximately 1 minute following vaginal penetration and before the individual wishes it`,weight:1},B:{text:`The symptom must have been present for at least 6 months and must be experienced on almost all or all occasions of sexual activity`,weight:.9}}}}},p={name:`Dissociative Disorders`,disorders:{"Dissociative Identity Disorder":{code:`300.14`,criteria:{A:{text:`Disruption of identity characterized by two or more distinct personality states`,weight:1},B:{text:`Recurrent gaps in the recall of everyday events, important personal information, or traumatic events that are inconsistent with ordinary forgetting`,weight:.9},C:{text:`The symptoms cause clinically significant distress or impairment`,weight:.9}}},"Dissociative Amnesia":{code:`300.12`,criteria:{A:{text:`An inability to recall important autobiographical information, usually of a traumatic or stressful nature, that is inconsistent with ordinary forgetting`,weight:1},B:{text:`The symptoms cause clinically significant distress or impairment`,weight:.9}}},"Depersonalization/Derealization Disorder":{code:`300.6`,criteria:{A:{text:`The presence of persistent or recurrent experiences of depersonalization, derealization, or both`,weight:1},B:{text:`During the depersonalization or derealization experiences, reality testing remains intact`,weight:.9},C:{text:`The symptoms cause clinically significant distress or impairment`,weight:.9}}}}},m={name:`Somatic Symptom and Related Disorders`,disorders:{"Somatic Symptom Disorder":{code:`300.82`,criteria:{A:{text:`One or more somatic symptoms that are distressing or result in significant disruption of daily life`,weight:1},B:{text:`Excessive thoughts, feelings, or behaviors related to the somatic symptoms or associated health concerns`,weight:.9},C:{text:`Although any one somatic symptom may not be continuously present, the state of being symptomatic is persistent (typically more than 6 months)`,weight:.9}}},"Illness Anxiety Disorder":{code:`300.7`,criteria:{A:{text:`Preoccupation with having or acquiring a serious illness`,weight:1},B:{text:`Somatic symptoms are not present or, if present, are only mild in intensity`,weight:.9},C:{text:`There is a high level of anxiety about health, and the individual is easily alarmed about personal health status`,weight:.9}}},"Conversion Disorder (Functional Neurological Symptom Disorder)":{code:`300.11`,criteria:{A:{text:`One or more symptoms of altered voluntary motor or sensory function`,weight:1},B:{text:`Clinical findings provide evidence of incompatibility between the symptom and recognized neurological or medical conditions`,weight:.9},C:{text:`The symptom or deficit is not better explained by another medical or mental disorder`,weight:.9}}},"Factitious Disorder":{code:`300.19`,criteria:{A:{text:`Falsification of physical or psychological signs or symptoms, or induction of injury or disease, associated with identified deception`,weight:1},B:{text:`The individual presents himself or herself to others as ill, impaired, or injured`,weight:.9},C:{text:`The deceptive behavior is evident even in the absence of obvious external rewards`,weight:.9}}}}},h={name:`Schizophrenia Spectrum and Other Psychotic Disorders`,disorders:{Schizophrenia:{code:`295.90`,criteria:{A:{text:`Two or more of the following, each present for a significant portion of time during a 1-month period (or less if successfully treated)`,threshold:2,symptoms:[{id:`delusions`,text:`Delusions`,weight:1},{id:`hallucinations`,text:`Hallucinations`,weight:1},{id:`disorganized_speech`,text:`Disorganized speech`,weight:.9},{id:`grossly_disorganized`,text:`Grossly disorganized or catatonic behavior`,weight:.9},{id:`negative_symptoms`,text:`Negative symptoms (diminished emotional expression or avolition)`,weight:.9}]},B:{text:`For a significant portion of the time since the onset of the disturbance, level of functioning in one or more major areas is markedly below the level achieved prior to onset`,weight:.9},C:{text:`Continuous signs of the disturbance persist for at least 6 months`,weight:.9}}},"Schizoaffective Disorder":{code:`295.70`,criteria:{A:{text:`An uninterrupted period of illness during which there is a major mood episode (major depressive or manic) concurrent with Criterion A of schizophrenia`,weight:1},B:{text:`Delusions or hallucinations for 2 or more weeks in the absence of a major mood episode during the lifetime duration of the illness`,weight:.9},C:{text:`Symptoms that meet criteria for a major mood episode are present for the majority of the total duration of the active and residual portions of the illness`,weight:.9}}},"Schizophreniform Disorder":{code:`295.40`,criteria:{A:{text:`Two or more of: delusions, hallucinations, disorganized speech, grossly disorganized or catatonic behavior, negative symptoms`,threshold:2,weight:1},B:{text:`An episode of the disorder lasts at least 1 month but less than 6 months`,weight:.9}}},"Brief Psychotic Disorder":{code:`298.8`,criteria:{A:{text:`Presence of one or more of: delusions, hallucinations, disorganized speech, grossly disorganized or catatonic behavior`,weight:1},B:{text:`Duration of an episode of the disturbance is at least 1 day but less than 1 month, with eventual full return to premorbid level of functioning`,weight:1}}},"Delusional Disorder":{code:`297.1`,criteria:{A:{text:`The presence of one or more delusions with a duration of 1 month or longer`,weight:1},B:{text:`Criterion A for schizophrenia has never been met`,weight:.9},C:{text:`Apart from the impact of the delusion(s) or its ramifications, functioning is not markedly impaired, and behavior is not obviously bizarre or odd`,weight:.8}}}}},g={mood:{depressed_mood:[`Over the past 2 weeks, how often have you felt down, depressed, or hopeless?`,`To what extent have you experienced persistent sadness or low mood?`],anhedonia:[`How much have you lost interest or pleasure in activities you usually enjoy?`,`To what degree have you found it difficult to feel pleasure or satisfaction?`],fatigue:[`How often have you felt tired or had little energy, even after adequate rest?`,`To what extent has fatigue interfered with your daily activities?`],elevated_mood:[`Have you experienced periods of unusually elevated, euphoric, or irritable mood?`,`To what extent have you felt unusually high or 'wired'?`]},anxiety:{worry:[`How often do you find yourself worrying excessively about various aspects of your life?`,`To what extent do you have difficulty controlling your worries?`],restlessness:[`How often do you feel restless, keyed up, or on edge?`,`To what degree do you experience physical restlessness or tension?`],panic:[`Have you experienced sudden episodes of intense fear or discomfort?`,`How often have you had panic attacks?`]},trauma:{intrusion:[`How often do you experience unwanted, distressing memories of a traumatic event?`,`To what extent do you have flashbacks or feel as if the trauma is happening again?`],avoidance:[`How much do you avoid reminders of a traumatic experience?`,`To what degree do you avoid thoughts, feelings, or conversations about trauma?`]}},_={mood:{depressed_mood:`Everyday read: feeling down, empty, or hopeless on most days.`,anhedonia:`Everyday read: things that used to feel good barely register or feel flat.`,weight_change:`Everyday read: noticeable change in weight or appetite without trying.`,sleep_disturbance:`Everyday read: trouble sleeping, waking a lot, or sleeping far more than usual.`,psychomotor:`Everyday read: feeling physically “wired” or slowed down, noticeable to others.`,fatigue:`Everyday read: drained or low energy most days, not just tired after a busy week.`,worthlessness:`Everyday read: harsh self-blame, guilt, or feeling like a failure.`,concentration:`Everyday read: brain fog, trouble focusing, or decisions feel stuck.`,suicidal:`Everyday read: thoughts of death, wishing you were not here, or harming yourself. If you are in immediate danger, contact local emergency services.`,poor_appetite:`Everyday read: eating much less or much more than usual for you.`,insomnia_hypersomnia:`Everyday read: trouble sleeping or sleeping far more than usual.`,low_energy:`Everyday read: low drive or stamina most of the time.`,low_self_esteem:`Everyday read: seeing yourself as inadequate or “not enough” most days.`,poor_concentration:`Everyday read: hard to focus or make even small decisions.`,hopelessness:`Everyday read: a stuck sense that things will not get better.`,elevated_mood:`Everyday read: unusually “high,” irritable, or revved up for you—not just a good day.`,increased_activity:`Everyday read: unusually driven, busy, or restless energy that is hard to dial down.`,grandiosity:`Everyday read: feeling special, bulletproof, or vastly more capable than usual.`,decreased_sleep:`Everyday read: feeling rested on far less sleep than normal for you.`,pressured_speech:`Everyday read: talking fast or nonstop, hard for others to interrupt.`,flight_ideas:`Everyday read: thoughts racing or jumping topic to topic in a way that feels hard to steer.`,distractibility:`Everyday read: pulled off-task by every noise, thought, or sidebar.`,risky_behavior:`Everyday read: impulsive choices (money, sex, speed, substances) with painful fallout.`,affective_lability:`Everyday read: moods swing hard and fast (fine to furious or tearful) around your cycle.`,irritability_anger:`Everyday read: short fuse, snappiness, or anger that feels bigger than the trigger.`,depressed_mood_pmdd:`Everyday read: clear low mood in the days before your period, better after it starts.`,anxiety_pmdd:`Everyday read: keyed-up, tense, or worried more than usual before your period.`,decreased_interest_pmdd:`Everyday read: usual activities feel “meh” before your period.`,difficulty_concentration_pmdd:`Everyday read: focus tanks in the days before your period.`,lethargy_pmdd:`Everyday read: heavy fatigue or “can’t get going” before your period.`,change_appetite_pmdd:`Everyday read: much more or much less hunger before your period.`,hypersomnia_insomnia_pmdd:`Everyday read: sleeping way more or way less before your period.`,overwhelmed_pmdd:`Everyday read: feeling swamped or not in control before your period.`,physical_symptoms_pmdd:`Everyday read: body symptoms like bloating or soreness before your period.`},anxiety:{restlessness:`Everyday read: on edge, keyed up, or unable to settle.`,easily_fatigued:`Everyday read: wiped out even when the day was not physically hard.`,difficulty_concentrating:`Everyday read: mind goes blank or you bounce away from tasks.`,irritability:`Everyday read: quick to snap or feel annoyed.`,muscle_tension:`Everyday read: clenched jaw, tight shoulders, or sore muscles from tension.`,sleep_disturbance_anx:`Everyday read: trouble falling or staying asleep, or unrested sleep.`},trauma:{recurrent_memories:`Everyday read: upsetting memories pop in even when you try not to think about them.`,recurrent_dreams:`Everyday read: distressing dreams tied to what happened.`,dissociative_reactions:`Everyday read: sudden “flashback” moments where it feels like it is happening again.`,psychological_distress:`Everyday read: reminders (places, sounds, people) spike anxiety or panic.`,physiological_reactions:`Everyday read: heart racing, sweating, or nausea when reminded.`,avoid_memories:`Everyday read: working hard not to think or talk about what happened.`,avoid_external:`Everyday read: steering clear of people, places, or media that remind you.`,amnesia:`Everyday read: big gaps in what you remember about the event.`,negative_beliefs:`Everyday read: harsh beliefs about yourself, others, or the world after what happened.`,distorted_blame:`Everyday read: blaming yourself or others in ways that feel stuck or extreme.`,negative_emotional:`Everyday read: fear, anger, guilt, or shame that will not lift.`,diminished_interest:`Everyday read: activities you used to care about feel pointless.`,detachment:`Everyday read: feeling cut off from people or like you are watching life from outside.`,inability_positive:`Everyday read: joy, love, or calm feel blocked or very faint.`,irritable_behavior:`Everyday read: short fuse, arguments, or lashing out.`,reckless_behavior:`Everyday read: risky choices that are not like your usual self.`,hypervigilance:`Everyday read: scanning for danger even in ordinary situations.`,exaggerated_startle:`Everyday read: big jump response to sudden noise or surprise.`,concentration_problems:`Everyday read: trouble staying on task or holding attention.`,sleep_disturbance_ptsd:`Everyday read: nightmares, trouble sleeping, or not feeling rested.`},substance:{tolerance:`Everyday read: needing more of the substance to get the same effect.`,withdrawal:`Everyday read: feeling sick, off, or not yourself when you cut down or stop.`,taken_larger:`Everyday read: using more or longer than you meant to.`,persistent_desire:`Everyday read: trying to cut back but not sticking with it.`,time_spent:`Everyday read: a lot of life goes to getting, using, or recovering.`,important_activities:`Everyday read: skipping work, relationships, or hobbies because of use.`,continued_despite:`Everyday read: keeping on even when you know it is hurting you.`,craving:`Everyday read: strong urges that are hard to ignore.`},schizophrenia:{delusions:`Everyday read: fixed beliefs that others do not share, hard to shake even with evidence.`,hallucinations:`Everyday read: sensing things (voices, visions) that others do not perceive.`,disorganized_speech:`Everyday read: train of thought is hard to follow when you talk.`,grossly_disorganized:`Everyday read: behavior looks chaotic, frozen, or odd to others.`,negative_symptoms:`Everyday read: flat expression, low motivation, or pulling back from life.`}},v=[{primary:`depressed_mood`,contradictory:`I generally feel optimistic and positive about my future`,weight:.8},{primary:`anhedonia`,contradictory:`I regularly experience joy and satisfaction in my activities`,weight:.8},{primary:`worry`,contradictory:`I rarely worry about things beyond my immediate control`,weight:.7},{primary:`elevated_mood`,contradictory:`My mood has been stable and consistent`,weight:.8},{primary:`panic`,contradictory:`I rarely experience sudden intense fear or panic`,weight:.7}],y={high_probability:.75,moderate_probability:.5,low_probability:.25,requires_sub_inquiry:.4},b={"Major Depressive Disorder":{severity:[`How would you rate the severity of your depressive symptoms?`,`To what extent do these symptoms interfere with your work, relationships, or daily functioning?`],duration:[`How long have you been experiencing these symptoms?`,`Have these symptoms been continuous or episodic?`],specifiers:[`Have you experienced any psychotic symptoms (delusions or hallucinations)?`,`Do you experience seasonal patterns in your mood?`]},"Bipolar I Disorder":{duration:[`How long do your elevated mood episodes typically last?`,`How long do your depressed episodes typically last?`],severity:[`During elevated mood periods, to what extent do your symptoms interfere with functioning?`,`Have you ever required hospitalization during mood episodes?`]},"Generalized Anxiety Disorder":{duration:[`How long have you been experiencing excessive worry?`,`Have these symptoms been constant or episodic?`],triggers:[`What situations or thoughts typically trigger your anxiety?`,`Do you notice patterns in when your anxiety is worse?`]},"Posttraumatic Stress Disorder":{trauma:[`What type of traumatic event(s) have you experienced?`,`How long ago did the traumatic event(s) occur?`],current:[`How often do you currently experience trauma-related symptoms?`,`Are there specific triggers that remind you of the trauma?`]}},x={mood_anxiety:{name:`Mood-Anxiety Comorbidity`,disorders:[`Major Depressive Disorder`,`Generalized Anxiety Disorder`,`Panic Disorder`,`Social Anxiety Disorder`,`Persistent Depressive Disorder`],triggers:{threshold:.5,message:`Mood and anxiety disorders frequently co-occur. Additional refinement questions will help differentiate primary vs. secondary symptoms.`}},trauma_mood_anxiety:{name:`Trauma-Mood-Anxiety Comorbidity`,disorders:[`Posttraumatic Stress Disorder`,`Major Depressive Disorder`,`Generalized Anxiety Disorder`,`Panic Disorder`],triggers:{threshold:.5,message:`Trauma-related disorders often co-occur with mood and anxiety symptoms. Refined assessment can help identify primary trauma responses vs. secondary mood/anxiety.`}},personality_mood:{name:`Personality-Mood Comorbidity`,disorders:[`Borderline Personality Disorder`,`Major Depressive Disorder`,`Bipolar I Disorder`,`Bipolar II Disorder`,`Persistent Depressive Disorder`],triggers:{threshold:.55,message:`Personality disorders and mood disorders often co-occur, particularly Borderline Personality with depression/bipolar. Additional assessment needed for differential diagnosis.`}},substance_comorbidity:{name:`Substance-Mental Health Comorbidity`,disorders:[`Substance Use Disorder`,`Major Depressive Disorder`,`Generalized Anxiety Disorder`,`Bipolar I Disorder`,`Borderline Personality Disorder`],triggers:{threshold:.5,message:`Substance use disorders frequently co-occur with mood, anxiety, and personality disorders. Determining primary vs. substance-induced symptoms requires careful assessment.`}},ocd_comorbidity:{name:`OCD Comorbidity`,disorders:[`Obsessive-Compulsive Disorder`,`Major Depressive Disorder`,`Generalized Anxiety Disorder`,`Body Dysmorphic Disorder`],triggers:{threshold:.5,message:`OCD and related disorders often co-occur with depression and anxiety. Refinement questions will help distinguish OCD-specific symptoms from generalized anxiety.`}},eating_comorbidity:{name:`Eating Disorder Comorbidity`,disorders:[`Anorexia Nervosa`,`Bulimia Nervosa`,`Binge-Eating Disorder`,`Major Depressive Disorder`,`Generalized Anxiety Disorder`,`Borderline Personality Disorder`],triggers:{threshold:.5,message:`Eating disorders frequently co-occur with mood, anxiety, and personality disorders. Additional assessment needed to identify primary eating disorder vs. secondary symptoms.`}},bipolar_spectrum:{name:`Bipolar Spectrum Differentiation`,disorders:[`Bipolar I Disorder`,`Bipolar II Disorder`,`Cyclothymic Disorder`,`Major Depressive Disorder`],triggers:{threshold:.45,message:`Multiple bipolar spectrum or mood disorders detected. Refined questions about hypomanic/manic episodes needed for accurate differentiation.`}},personality_clusters:{name:`Personality Disorder Cluster Comorbidity`,disorders:[`Borderline Personality Disorder`,`Narcissistic Personality Disorder`,`Antisocial Personality Disorder`,`Histrionic Personality Disorder`,`Avoidant Personality Disorder`,`Dependent Personality Disorder`],triggers:{threshold:.5,message:`Multiple personality disorder indicators detected. Refined assessment needed as personality disorders can share overlapping symptoms but require distinct diagnostic criteria.`}}},S={mood_anxiety:[`Which came first - the depressed mood or the excessive worry/anxiety?`,`When you feel anxious, does it typically precede or follow depressive episodes?`,`Do your anxiety symptoms persist even when your mood is stable?`,`Are your worries primarily about future events (anxiety) or past/current situations (depression)?`,`When you experience physical symptoms (racing heart, tension), do they occur with worry (anxiety) or regardless of mood state (depression)?`],trauma_mood_anxiety:[`Did your mood/anxiety symptoms begin before or after the traumatic event?`,`Are your depressive symptoms specifically related to trauma memories, or do they occur independently?`,`When you feel anxious, are you specifically worried about trauma recurrence, or is it generalized worry?`,`Do your symptoms improve or worsen when trauma reminders are present?`,`Are your mood symptoms part of trauma-related emotional numbing, or separate depressive episodes?`],personality_mood:[`Have your mood symptoms been present since adolescence/early adulthood (personality) or developed later (mood disorder)?`,`Do your relationships show patterns of instability regardless of mood state (personality) or only during mood episodes?`,`Do you experience rapid mood shifts within hours/days (personality) or sustained mood episodes lasting weeks (mood disorder)?`,`Are your depressive symptoms triggered by relationship events (personality) or occur independently (mood disorder)?`,`Do you have a consistent sense of self, or does your identity feel unstable regardless of mood?`],substance_comorbidity:[`Did your mood/anxiety symptoms begin before or after substance use increased?`,`Do your symptoms persist during periods of sobriety, or only during/after substance use?`,`Have you attempted to self-medicate mood/anxiety symptoms with substances?`,`Do your depressive symptoms improve or worsen with substance use?`,`Are your symptoms consistent with substance withdrawal effects, or do they occur independently?`],bipolar_spectrum:[`Have you experienced periods where you felt unusually energized, confident, or needed less sleep?`,`During elevated mood periods, did you engage in risky behaviors or make impulsive decisions?`,`Do you experience rapid cycling between high and low moods, or sustained episodes?`,`Have others commented on your behavior being unusual during your 'high' periods?`,`Do your elevated mood periods last days/weeks, or just hours?`,`During elevated moods, do you feel more irritable than euphoric, or vice versa?`,`Have your elevated moods caused problems in relationships, work, or legal issues?`],ocd_comorbidity:[`Are your worries repetitive, intrusive thoughts that feel foreign (OCD) or realistic concerns (anxiety)?`,`Do you perform rituals or mental acts to reduce anxiety from your thoughts?`,`Are your anxiety symptoms triggered by specific obsessions, or are they generalized?`,`Do your repetitive thoughts cause distress because they're unwanted (OCD) or because they're realistic (anxiety)?`,`Have you tried to suppress or neutralize your repetitive thoughts?`],eating_comorbidity:[`Did your mood/anxiety symptoms begin before or after eating disorder behaviors?`,`Do your depressive symptoms improve or worsen with eating disorder behaviors?`,`Are your body image concerns specifically about weight/shape (eating disorder) or general appearance (BDD)?`,`Do you restrict/binge as a way to manage emotions, or is it independent of mood?`,`Have you experienced significant weight changes that correlate with mood symptoms?`],personality_clusters:[`How long have you noticed these personality traits - since adolescence or developed recently?`,`Do these patterns occur across all relationships and situations, or only in specific contexts?`,`When you're not in a crisis, do these patterns still affect your functioning?`,`Have others consistently described you in similar ways throughout your life?`,`Do you recognize these patterns as problematic, or do they feel normal to you?`]},C={moderate_comorbidity:.4,high_comorbidity:.6,require_refinement:.45,differential_diagnosis:.35},w={"Major Depressive Disorder":{severity_refinement:[`On a scale of 0-10, how would you rate the intensity of your depressed mood?`,`How many days in the past week have you experienced significant depressed mood?`,`Do your depressive symptoms follow a daily pattern (worse in morning vs. evening)?`,`Have you noticed seasonal patterns in your mood (worse in winter/summer)?`],functional_impact:[`To what extent do your symptoms interfere with your ability to work or study?`,`How much have your relationships been affected by your mood symptoms?`,`Are you able to maintain basic self-care (hygiene, eating, sleeping) during episodes?`,`Have you had to take time off work or school due to your symptoms?`],symptom_clarification:[`When you experience anhedonia (loss of interest), is it complete inability to feel pleasure, or reduced capacity?`,`Are your concentration problems due to intrusive thoughts, mental fog, or distractibility?`,`Do your sleep problems involve difficulty falling asleep, staying asleep, or early morning awakening?`,`Have you experienced changes in appetite leading to significant weight changes (5%+ body weight)?`],differential_clarification:[`Have you ever experienced periods of elevated mood, increased energy, or decreased need for sleep?`,`Did your symptoms begin after a specific life event, or gradually over time?`,`Have you experienced any traumatic events that might relate to your current symptoms?`,`Are you currently using any substances (alcohol, drugs, medications) that might affect your mood?`]},"Bipolar I Disorder":{mania_clarification:[`During elevated mood periods, how many hours of sleep do you need per night?`,`Do you experience racing thoughts or flight of ideas during elevated periods?`,`Have you engaged in reckless spending, sexual behavior, or business investments during elevated moods?`,`During elevated periods, do you feel invincible or like you have special powers/connections?`,`How long do your elevated mood episodes typically last (days, weeks, months)?`],depression_clarification:[`Do you experience depressive episodes between elevated periods?`,`How would you compare the severity of your depressions vs. your elevated periods?`,`Do depressive episodes follow elevated periods, or occur independently?`],functional_impact:[`Have your elevated moods caused problems at work (being fired, conflicts, poor judgment)?`,`Have your elevated moods affected your relationships (conflicts, breakups, relationship damage)?`,`Have you had legal or financial problems during elevated mood periods?`,`Have you required hospitalization during mood episodes?`]},"Bipolar II Disorder":{hypomania_detection:[`Have you experienced periods of increased energy and confidence that lasted at least 4 days?`,`During these periods, did you need less sleep but felt well-rested?`,`Did others notice these changes in your behavior or mood?`,`Did these periods cause any problems in your life, or were they purely positive?`,`Do these elevated periods alternate with depressive episodes?`],depression_clarification:[`How severe are your depressive episodes compared to your elevated periods?`,`Do you experience more time in depression or hypomania?`,`Have you ever experienced full mania (not just hypomania)?`]},"Generalized Anxiety Disorder":{worry_patterns:[`How many hours per day do you spend worrying?`,`Do your worries focus on specific themes (health, finances, relationships) or shift between topics?`,`Are your worries about realistic problems, or worst-case scenarios that are unlikely?`,`Do you find it easier to worry about one thing after resolving another?`,`Have you been a worrier your entire life, or did this pattern develop more recently?`],physical_symptoms:[`Which physical symptoms do you experience most: muscle tension, restlessness, fatigue, or sleep problems?`,`Do physical symptoms occur even when you're not actively worrying?`,`Have you had medical tests to rule out physical causes for your symptoms?`,`Do physical symptoms improve or worsen with relaxation techniques?`],control_clarification:[`Have you tried specific strategies to stop worrying (distraction, reassurance-seeking, avoidance)?`,`When you try to stop worrying, do worries come back stronger?`,`Do you feel like worrying helps you prepare for problems, or is it purely distressing?`]},"Panic Disorder":{attack_characteristics:[`How long do your panic attacks typically last (minutes to hours)?`,`Do attacks come on suddenly (within minutes) or build gradually?`,`During attacks, which symptoms are most prominent: physical (heart racing, sweating) or cognitive (fear of dying, losing control)?`,`Have you had attacks in situations where you previously felt safe?`,`Do attacks occur during sleep, or only while awake?`],agoraphobia_clarification:[`Have you begun avoiding places where you've had panic attacks?`,`Do you avoid leaving home alone, or only specific situations?`,`Would you feel safer if someone you trust accompanied you to feared situations?`,`Has avoidance significantly restricted your activities or lifestyle?`],anticipatory_anxiety:[`How much time do you spend worrying about having another attack?`,`Do you monitor your body for physical symptoms that might signal an attack?`,`Have you developed safety behaviors or rituals to prevent attacks?`]},"Posttraumatic Stress Disorder":{trauma_clarification:[`What type of traumatic event(s) did you experience (single event, repeated events, chronic exposure)?`,`How long ago did the trauma occur?`,`Were you directly involved, witnessed it, or learned about it happening to a close other?`,`Did you feel your life or safety was threatened during the trauma?`],intrusion_clarification:[`How frequently do you experience intrusive memories or flashbacks?`,`Are flashbacks so vivid that you lose awareness of your current surroundings?`,`Do trauma-related nightmares cause you to wake up in distress?`,`Are there specific triggers that reliably cause intrusive symptoms?`],avoidance_clarification:[`What specific reminders do you avoid (places, people, conversations, activities)?`,`Have you avoided trauma-related thoughts or memories, or only external reminders?`,`Has avoidance caused you to change your lifestyle significantly?`],cognitive_mood_clarification:[`Do you blame yourself, others, or the world for the trauma?`,`Have your beliefs about safety, trust, or control changed since the trauma?`,`Do you experience persistent negative emotions (fear, anger, shame, guilt)?`,`Have you lost interest in activities you enjoyed before the trauma?`],arousal_clarification:[`Are you constantly scanning your environment for threats (hypervigilance)?`,`Do you startle easily, even in safe situations?`,`Do you experience irritability or angry outbursts that are out of character?`,`Have you engaged in reckless or self-destructive behaviors since the trauma?`]},"Borderline Personality Disorder":{relationship_patterns:[`Do your relationships alternate between idealizing and devaluing partners?`,`Do you fear abandonment even when there's no evidence of it?`,`Have most of your close relationships been intense but unstable?`,`Do you find it difficult to be alone, or do you prefer solitude?`,`When relationships end, do you experience extreme distress that feels unbearable?`],identity_clarification:[`Do you have a clear sense of who you are, or does it feel like it changes frequently?`,`Have your values, goals, or career aspirations changed dramatically over time?`,`Do you feel empty or unsure of your identity when not in a relationship?`,`Do you adapt your personality to match who you're with?`],emotional_instability:[`How quickly do your moods change (within hours, days, or weeks)?`,`Are your emotional reactions disproportionate to the situation?`,`Do you experience intense emotions that feel overwhelming and uncontrollable?`,`How long do intense emotional states typically last?`],impulsivity_clarification:[`Have you engaged in risky behaviors (unsafe sex, reckless driving, substance use, spending)?`,`Do you make impulsive decisions that you later regret?`,`Have you engaged in self-harm or suicidal behavior, especially during emotional distress?`,`Do you act impulsively to relieve emotional pain, even if it causes long-term problems?`]},"Obsessive-Compulsive Disorder":{obsession_clarification:[`Are your repetitive thoughts unwanted and intrusive, or are they voluntary worries?`,`Do your thoughts feel like they come from outside yourself, or are they clearly your own?`,`Do your thoughts focus on specific themes (contamination, harm, symmetry, religious/moral)?`,`Have you tried to suppress or neutralize these thoughts?`,`Do your thoughts cause distress because they're unwanted (ego-dystonic)?`],compulsion_clarification:[`Do you perform repetitive behaviors or mental acts in response to your obsessions?`,`Do these behaviors feel necessary to prevent something bad from happening?`,`How much time do you spend on compulsive behaviors per day?`,`Have compulsive behaviors significantly interfered with your daily functioning?`,`If you try to resist compulsions, does your anxiety increase until you perform them?`],insight_clarification:[`Do you recognize that your obsessions/compulsions are excessive or unreasonable?`,`Have you sought reassurance from others about your obsessions?`,`Do you have good, fair, poor, or absent insight into your symptoms?`]},"Social Anxiety Disorder":{fear_clarification:[`What specific social situations do you fear (public speaking, eating in public, meeting new people, etc.)?`,`Do you fear all social situations, or only specific types (performance vs. interaction)?`,`Are you afraid of being judged, embarrassed, or rejected?`,`Do you worry that others will notice your anxiety symptoms (blushing, sweating, trembling)?`],avoidance_clarification:[`How often do you avoid feared social situations?`,`Have you avoided social situations even when they were important to you?`,`Do you use safety behaviors (drinking alcohol, avoiding eye contact, preparing excessively)?`,`Has social avoidance significantly limited your life (career, relationships, education)?`],performance_clarification:[`Do your symptoms occur only during performance situations, or also in everyday interactions?`,`During social situations, are you focused on your own performance or others' reactions?`,`Do you experience physical symptoms (blushing, sweating, trembling) in social situations?`]}},T={depression_vs_persistent_depression:[`Have your depressive symptoms been continuous for at least 2 years, or episodic?`,`Do your symptoms meet full criteria for major depression, or are they milder but chronic?`,`Have you had periods of normal mood lasting 2+ months, or has low mood been persistent?`],bipolar_vs_unipolar_depression:[`Have you ever experienced periods of elevated mood, increased energy, or decreased need for sleep?`,`During elevated periods, did you feel unusually confident, creative, or productive?`,`Have others commented on changes in your behavior during elevated periods?`,`Have you been treated for depression with antidepressants that caused mood elevation or irritability?`],anxiety_vs_ocd:[`Are your worries realistic concerns about daily life, or intrusive thoughts that feel foreign?`,`Do you perform rituals or mental acts to reduce anxiety from your thoughts?`,`Are your anxiety symptoms triggered by specific obsessions, or are they generalized?`],ptsd_vs_anxiety_depression:[`Did your symptoms begin after a specific traumatic event?`,`Do you experience intrusive memories, flashbacks, or nightmares related to trauma?`,`Do you actively avoid trauma reminders, or just experience generalized anxiety/depression?`],personality_vs_mood:[`Have these patterns been present since adolescence, or developed later in life?`,`Do symptoms occur across all situations, or only during mood episodes?`,`Do you have a stable sense of self, or does it fluctuate with mood?`]},E={mood:n,anxiety:r,trauma:i,personality:a,ocd:o,eating:s,substance:c,neurocognitive:l,neurodevelopmental:u,sleep:d,sexual:f,dissociative:p,somatic:m,schizophrenia:h};export{e as CATEGORY_DESCRIPTIONS,t as CATEGORY_GUIDE_QUESTIONS,x as COMORBIDITY_GROUPS,S as COMORBIDITY_REFINEMENT_QUESTIONS,T as DIFFERENTIAL_QUESTIONS,E as DSM5_CATEGORIES,C as MULTI_BRANCHING_THRESHOLDS,_ as PLAIN_LANGUAGE_HINTS,g as QUESTION_TEMPLATES,w as REFINED_QUESTIONS,y as SCORING_THRESHOLDS,b as SUB_INQUIRY_QUESTIONS,v as VALIDATION_PAIRS};